# Creating Criminal Justice Measures
## Before 18 Incarceration
B$NMI_B18<-rowSums(data.frame(B$NMI_Age7,B$NMI_Age8,B$NMI_Age9,
                              B$NMI_Age10,B$NMI_Age11,B$NMI_Age12,
                              B$NMI_Age13,B$NMI_Age14,B$NMI_Age15,
                              B$NMI_Age16,B$NMI_Age17), na.rm = T)
table(B$NMI_B18>=1)
## After 18 Incarceration
B$NMI_A18<-rowSums(data.frame(B$NMI_Age18,B$NMI_Age19,B$NMI_Age20,
                              B$NMI_Age21,B$NMI_Age22,B$NMI_Age23,
                              B$NMI_Age24,B$NMI_Age25,B$NMI_Age26,
                              B$NMI_Age27,B$NMI_Age28,B$NMI_Age29,
                              B$NMI_Age30,
                              B$NMI_Age31,B$NMI_Age32,B$NMI_Age33,
                              B$NMI_Age34,B$NMI_Age35,B$NMI_Age36,
                              B$NMI_Age37,B$NMI_Age38), na.rm = T)

## Before 18 Arrest
B$NA_B18<-rowSums(data.frame(B$NA_Age7,B$NA_Age8,B$NA_Age9,
                             B$NA_Age10,B$NA_Age11,B$NA_Age12,
                             B$NA_Age13,B$NA_Age14,B$NA_Age15,
                             B$NA_Age16,B$NA_Age17), na.rm = T)
## After 18 Arrest
B$NA_A18<-rowSums(data.frame(B$NA_Age18,B$NA_Age19,B$NA_Age20,
                             B$NA_Age21,B$NA_Age22,B$NA_Age23,
                             B$NA_Age24,B$NA_Age25,B$NA_Age26,
                             B$NA_Age27,B$NA_Age28,B$NA_Age29,
                             B$NA_Age30,
                             B$NA_Age31,B$NA_Age32,B$NA_Age33,
                             B$NA_Age34,B$NA_Age35,B$NA_Age36,
                             B$NA_Age37,B$NA_Age38), na.rm = T)

## Creating Dichotomies

table(B$NA_B18)
table(B$NMI_B18)
table(B$JIJF)

B$NA_B18[B$NMI_B18>=1 & B$NA_B18 == 0]<-NA
table(B$NA_B18,useNA = "always")

B$B18_NOARREST<-NA
B$B18_NOARREST[B$NA_B18 == 0 & B$NMI_B18 == 0]<-1
B$B18_NOARREST[B$NA_B18 >= 1 | B$NMI_B18 >= 1]<-0
table(B$B18_NOARREST,useNA = "always")

B$B18_ARREST<-NA
B$B18_ARREST[B$NA_B18 >= 1 & B$NMI_B18 == 0]<-1
B$B18_ARREST[B$NA_B18 == 0 & B$NMI_B18 == 0]<-0
B$B18_ARREST[B$NMI_B18 >= 1]<-0
table(B$B18_ARREST,useNA = "always")

# Incarcerated in An Adult Facility Prior to their 18th birthday 
B$B18_INCAF<-NA
B$B18_INCAF[B$NMI_B18 >= 1]<-1
B$B18_INCAF[B$NA_B18 == 0 & B$NMI_B18 == 0]<-0
B$B18_INCAF[B$NA_B18 >= 1 & B$NMI_B18 == 0]<-0
table(B$B18_INCAF,useNA = "always")

table(B$NMI_B18>0,B$JIJF)


# Coding Out Classification 
names(B)
B$Classification[B$B18_NOARREST==1]<-1 # No Arrest 
table(B$Classification)
B$Classification[B$B18_ARREST==1]<-2 # Arrested
table(B$Classification)
B$Classification[B$JIJF==1]<-3 # Incarcerated in Juvenile Facility
table(B$Classification)
B$Classification[B$B18_INCAF==1]<-4 # Incarcerated in Adult Facility
table(B$Classification)
B$Classification<-as.factor(B$Classification)

