           set_prior("normal(0, 2.5)", class = "b", coef = "Weeks_Worked_02_19_RE"),
           set_prior("normal(0, 2.5)", class = "b", coef = "Hispanic"),
           set_prior("normal(0, 2.5)", class = "b", coef = "White"),
