           set_prior("normal(0, 2.5)", class = "b", coef = "BFEA97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "PHEALTH97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "BBPHH"),
           set_prior("normal(0, 2.5)", class = "b", coef = "CC1Y"),
           set_prior("normal(0, 2.5)", class = "b", coef = "HT97"),
