# Model (No Wave) ####
names(L)


get_prior(No_HealthI_03_21 ~ 1+as.factor(Classification)+NOArrests_02_19+MonthsIcar_02_19+General_H_02_19+Weeks_Worked_02_19_RE+
            Hispanic+White+Black+Male+Sample+PIB16+
            BMEA97+BFEA97+PHEALTH97+BBPHH+CC1Y+HT97+
            GH97+WW_97+NHIN_97+Ex_Medicaid_RE+(1|R0000100) , data = L)


Priors1<-c(set_prior("normal(0, 2.5)", class = "b", coef = "as.factorClassification2"),
           set_prior("normal(0, 2.5)", class = "b", coef = "as.factorClassification3"),
           set_prior("normal(0, 2.5)", class = "b", coef = "as.factorClassification4"),
           set_prior("normal(0, 2.5)", class = "b", coef = "NOArrests_02_19"),
           set_prior("normal(0, 2.5)", class = "b", coef = "MonthsIcar_02_19"),
           set_prior("normal(0, 2.5)", class = "b", coef = "General_H_02_19"),
           set_prior("normal(0, 2.5)", class = "b", coef = "Weeks_Worked_02_19_RE"),
           set_prior("normal(0, 2.5)", class = "b", coef = "Hispanic"),
           set_prior("normal(0, 2.5)", class = "b", coef = "White"),
           set_prior("normal(0, 2.5)", class = "b", coef = "Black"),
           set_prior("normal(0, 2.5)", class = "b", coef = "Sample"),
           set_prior("normal(0, 2.5)", class = "b", coef = "PIB16"),
           set_prior("normal(0, 2.5)", class = "b", coef = "BMEA97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "BFEA97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "PHEALTH97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "BBPHH"),
           set_prior("normal(0, 2.5)", class = "b", coef = "CC1Y"),
           set_prior("normal(0, 2.5)", class = "b", coef = "HT97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "GH97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "WW_97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "NHIN_97"),
           set_prior("normal(0, 2.5)", class = "b", coef = "Ex_Medicaid_RE"))


set.seed(1992)
random_id <- sample(unique(L$R0000100), 2500)

Short_Data<-L %>% filter(R0000100 %in% random_id)

table(Short_Data$Classification,Short_Data$Wave_Outcome)

M2<-brm(formula = No_HealthI_03_21~ as.factor(Classification)+
          NOArrests_02_19+MonthsIcar_02_19+General_H_02_19+Weeks_Worked_02_19_RE+
          Hispanic+White+Black+Male+Sample+PIB16+
          BMEA97+BFEA97+PHEALTH97+BBPHH+CC1Y+HT97+
          GH97+WW_97+NHIN_97+Ex_Medicaid_RE+(1|R0000100) , data = L, family = bernoulli(link = "logit"),
        prior = Priors1, iter = 20000, warmup = 10000, chains = 4, cores = 24,
        control = list(adapt_delta = 0.95, max_treedepth = 15))

summary(M2)
# Odds Ratio
exp(fixef(M2))


sink("No Health Insurance 2003-2021 (No Wave).txt")
print(summary(M2), digits = 5)
print("Odds Ratios")
print(exp(fixef(M2)), digits = 5)
print("Correlation matrix to test multicolinearity")
cov2cor(vcov(M2))
sink()

